module custom_logic (
    input m,
    input n,
    input o,
    input p,
    output reg obf_flag);

    always @(*) begin
        case ({m, n, o, p})
            4'b1111: obf_flag = 1;
            4'b0010: obf_flag = 0;
            4'b1101: obf_flag = 0;
            4'b0100: obf_flag = 1;
            4'b1010: obf_flag = 1;
            4'b0110: obf_flag = 0;
            4'b1001: obf_flag = 0;
            4'b0001: obf_flag = 1;
            4'b1100: obf_flag = 1;
            4'b0111: obf_flag = 0;
            default: obf_flag = 0;
        endcase
    end
endmodule
